const SITEMAP = "<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n<urlset xmlns=\"http://www.sitemaps.org/schemas/sitemap/0.9\">\n  <url><loc>https://carb-clean-truck-check.com/</loc><changefreq>weekly</changefreq><priority>1.0</priority></url>\n</urlset>";
